70	function tunnel_rewrite_url($url) {
71	    if (TUNNEL_SUBSITE_PATH !== '') {
72	        $url = str_replace(
73	            [
74	                TUNNEL_LOCAL_URL . TUNNEL_SUBSITE_PATH,
75	                TUNNEL_LOCAL_ALT . TUNNEL_SUBSITE_PATH,
76	                TUNNEL_LOCAL_NOPORT . TUNNEL_SUBSITE_PATH,
77	            ],
