/**
 * Resolve o permalink de uma página em runtime, opcionalmente via switch_to_blog.
 *
 * Uso: concertacao_resolve_url('atuacao/encontros') no contexto blog 1, ou
 *      concertacao_resolve_url('linha-do-tempo', 2) para uma página do blog 2.
 *
 * Falha-segura: se a página não existir, retorna `home_url('/' . $path)`
 * preservando o caminho — o item ainda renderiza e a navegação funciona via
 * rewrite do WP, embora o admin nunca deva chegar a esse fallback (auditar via
 * `WP_DEBUG_LOG` quando isso ocorrer).
 *
 * @param string $path  Path relativo sem leading slash (ex: 'sobre-nos/4-amazonias')
 * @param int    $blog  blog_id alvo; 0 = blog atual
 * @return string URL absoluta (com host atual; tunnel-url-rewrite.php cuida do scheme/host em dev)
 */
function concertacao_resolve_url( string $path, int $blog = 0 ): string {
    $switched = false;
    if ( $blog > 0 && function_exists( 'is_multisite' ) && is_multisite() && get_current_blog_id() !== $blog ) {
        switch_to_blog( $blog );
        $switched = true;
    }

    $page = get_page_by_path( $path );
    $url  = $page ? get_permalink( $page->ID ) : home_url( '/' . ltrim( $path, '/' ) . '/' );

    if ( $switched ) {
        restore_current_blog();
    }
    return $url;
}

function concertacao_shared_menu_items(): array {
    static $items = null;
    if ( $items !== null ) {
        return $items;
    }

    // ===================================================================
    // ESTRUTURA DO MENU PRINCIPAL
    // URLs resolvidas via concertacao_resolve_url() — slug → permalink real.
    // Único hardcoded: âncora #nucleogovernanca em /sobre-nos/ (não há hash
    // separado em get_permalink). Itens de Cultura usam blog_id=2.
    // ===================================================================

    $def   = [];
    $sobre = 90000;
    $atua  = 90005;
    $conh  = 90011;
    $cult  = 90015;

    // ── Sobre nós ──────────────────────────────────────────────────────
    $def[] = [ 'Sobre nós',             concertacao_resolve_url( 'sobre-nos' ) ];                                       // ID 90000
    $def[] = [ 'Rede',                  'https://www.concertacaoamazonia.com.br/sobre-nos/#nucleogovernanca', $sobre ]; // âncora — apex prod
    $def[] = [ '4 Amazônias',           concertacao_resolve_url( 'sobre-nos/4-amazonias' ),     $sobre ];
    $def[] = [ '5 Pilares',             concertacao_resolve_url( 'sobre-nos/5-pilares' ),       $sobre ];
    $def[] = [ 'Agenda Integradora',    concertacao_resolve_url( 'agenda-integradora' ),        $sobre ];

    // ── Atuação ────────────────────────────────────────────────────────
    $def[] = [ 'Atuação',               concertacao_resolve_url( 'atuacao' ) ];                                         // ID 90005
    $def[] = [ 'Encontros',             concertacao_resolve_url( 'atuacao/encontros' ),                  $atua ];
    $def[] = [ 'Grupos de Trabalho',    concertacao_resolve_url( 'atuacao/grupos-de-trabalho' ),         $atua ];
    $def[] = [ 'Iniciativas Estruturantes', concertacao_resolve_url( 'atuacao/iniciativas-estruturantes' ), $atua ];
    $def[] = [ 'Atuação Internacional', concertacao_resolve_url( 'atuacao/atuacao-internacional' ),      $atua ];
    $def[] = [ 'Perguntas e Respostas', concertacao_resolve_url( 'atuacao/faq' ),                        $atua ];

    // ── Conhecimento ───────────────────────────────────────────────────
    $def[] = [ 'Conhecimento',           concertacao_resolve_url( 'conhecimento' ) ];                                   // ID 90011
    $def[] = [ 'Espiral de Conhecimento',concertacao_resolve_url( 'conhecimento/espiral-de-conhecimento' ), $conh ];
    $def[] = [ 'Mapa de Plataformas',    concertacao_resolve_url( 'conhecimento/mapa-das-plataformas' ),    $conh ];
    $def[] = [ 'Publicações',            concertacao_resolve_url( 'conhecimento/publicacoes' ),             $conh ];

    // ── Cultura (blog_id=2) ────────────────────────────────────────────
    $def[] = [ 'Cultura',                        concertacao_resolve_url( '', 2 ) ];                                    // ID 90015 — home blog 2
    $def[] = [ 'Linha do Tempo',                 concertacao_resolve_url( 'linha-do-tempo',              2 ), $cult ];
    $def[] = [ 'Atlas Cultural das Amazônias',   concertacao_resolve_url( 'atlas-cultural-das-amazonias',2 ), $cult ];
    $def[] = [ 'Galeria',                        concertacao_resolve_url( 'galeria',                     2 ), $cult ];
    $def[] = [ 'Exposição Porosidades',          concertacao_resolve_url( 'porosidades',                 2 ), $cult ];
    $def[] = [ 'Exposição Cores do Futuro',      concertacao_resolve_url( 'exposicao-cores-do-futuro',   2 ), $cult ];
    $def[] = [ 'Exposição Poéticas do Possível', concertacao_resolve_url( 'poeticas-do-possivel',        2 ), $cult ];

    // ── Contato ────────────────────────────────────────────────────────
    $def[] = [ 'Contato',                concertacao_resolve_url( 'contato' ) ];

    $items = concertacao_build_menu_items( $def, 90000 );
    return $items;
}

